import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;

import java.util.Map;

@SpringBootApplication
@RestController
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/webhook")
    public ResponseEntity<String> handleWebhook(@RequestBody Map<String, Object> payload) {
        String url = (String) payload.get("url");
        String method = (String) payload.get("method");
        Map<String, Object> headers = (Map<String, Object>) payload.get("headers");
        Object body = payload.get("body");

        try {
            HttpHeaders httpHeaders = new HttpHeaders();
            if (headers != null) {
                headers.forEach((key, value) -> httpHeaders.add(key, value.toString()));
            }

            HttpEntity<Object> entity = new HttpEntity<>(body, httpHeaders);
            HttpMethod httpMethod = HttpMethod.valueOf(method.toUpperCase());

            ResponseEntity<String> response = restTemplate.exchange(url, httpMethod, entity, String.class);
            return ResponseEntity.ok(response.getBody());
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error fetching content: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        SpringApplication.run(WebhookHandler.class, args);
    }
}